- D: The passage states larvae settle on bare rock when grazing permits it.', NULL, 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"rw_subtype":"main_idea","rw_format":"passage_mc","dsat_blueprint_v1":true,"dsat_topic":"literature","generator":"generate-dsat-rw-expansion.mjs","explanation_v2":true,"blueprint_version":"dsat_blueprint_v1","challenged_problem":true,"difficulty_tier":"challenged","original":true}'::jsonb, now(), now())
